"""Performance benchmarks for the Golden Proj projection."""
from __future__ import annotations

import datetime

from typing import cast
from uuid import uuid4

from rationalevault.schema import EventRecord, EventType, EventMetadata

from .events import TaskCreatedPayload
from .projection import GoldenProjProjection


# Decision:
# All projections must include a benchmark to track events-per-second replay speed.
#
# Why:
# Replay speed directly dictates node startup time and branch switching latency.
# The benchmark ensures the core O(1) constraints of the reducer are maintained.

def test_benchmark_golden_proj_replay(benchmark):
    """Benchmark raw event replay speed for GoldenProj."""
    projection = GoldenProjProjection()
    
    # Pre-allocate events to isolate just the reduction speed
    num_events = 1000
    events = [
        EventRecord(
            event_sequence=i,
            id=uuid4(),
            project_id=uuid4(),
            stream_id="test-stream",
            version=i,
            event_type=cast(EventType, "TaskCreated"),
            metadata=EventMetadata(actor="test", source="test"),
            payload=TaskCreatedPayload(task_id=f"t-{i}", description="Work", owner="alice").to_dict(),
            parent_id=None,
            recorded_at=datetime.datetime.now(datetime.timezone.utc)
        )
        for i in range(num_events)
    ]

    def run_replay():
        return projection.reduce(events)

    # Benchmark the reduction
    final_state = benchmark(run_replay)
    assert len(final_state.tasks) == num_events
